import{_ as t,o as i,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"50A. Biometric Timekeeping","description":"","frontmatter":{"title":"50A. Biometric Timekeeping","eba":"Allied Health Professionals 2021-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/50A-biometric-timekeeping.md","filePath":"ebas/allied-health/hours-of-work/50A-biometric-timekeeping.md"}'),a={name:"ebas/allied-health/hours-of-work/50A-biometric-timekeeping.md"};function r(s,e,l,p,m,h){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_50a-biometric-timekeeping" tabindex="-1">50A. Biometric Timekeeping <a class="header-anchor" href="#_50a-biometric-timekeeping" aria-label="Permalink to &quot;50A. Biometric Timekeeping&quot;">​</a></h1><p><strong>50A.1</strong> It is acknowledged that biometric timekeeping is one way to provide accurate data for payroll purposes.</p><p><strong>50A.2</strong> For Employers others than those referred to at subclauses 50A.4 and 50A.5 below, where an Employee has a genuine difficulty in complying with biometric timekeeping requirements, including where the Employee holds privacy concerns, the Employer can only refuse an alternative timekeeping method for the reasons set out in subclause 50A.3.</p><p><strong>50A.3</strong> In the circumstances in subclause 50A.2, the Employer can only refuse an alternative timekeeping method if it:</p><p><strong>(a)</strong> will result in an unreasonable additional cost to the Employer; and</p><p><strong>(b)</strong> does not provide reasonably reliable data for payroll purposes.</p><p><strong>50A.4</strong> Employers who, at the date this Agreement comes into operation have biometric timekeeping (in whole or part of their organisation) and have an alternative timekeeping method will maintain an alternative timekeeping method.</p><p><strong>50A.5</strong> Employers who, at the date this Agreement comes into operation do not have biometric timekeeping will, in the event that it is introduced, have an alternative timekeeping method.</p><p><strong>50A.6</strong> In the event of any unforeseeable event that disrupts an Employer’s ability to offer an alternative (including on a temporary basis), the Employer will notify the Union for the purpose of discussions.</p>',9)])])}const g=t(a,[["render",r]]);export{d as __pageData,g as default};
